INSERT INTO public.templates_mensagens (id, tipo, titulo, descricao, assunto_email, corpo_email, corpo_sms, corpo_whatsapp, variaveis_disponiveis, ativo, ordem, created_at, updated_at)
VALUES
('a2d66935-95a6-4a7e-9295-6a93f105aa4c', 'lembrete_prazo', 'Lembrete de Prazo', 'Enviado dias antes do vencimento do prazo', '⚠️ LEMBRETE DE PRAZO - {{crianca_nome}}', '<h2>⏰ Lembrete de Prazo</h2><p>Olá <strong>{{responsavel_nome}}</strong>,</p><p>Faltam apenas <strong>{{dias_restantes}} dias</strong> para encerrar o prazo de matrícula de <strong>{{crianca_nome}}</strong>.</p><p><strong>Data limite:</strong> {{data_limite}}</p><p>Compareça à Secretaria o quanto antes para não perder a vaga!</p>', 'VAGOU: Faltam {{dias_restantes}} dias para o prazo de matricula de {{crianca_nome}}. Evite perder a vaga!', '⏰ *Lembrete de Prazo*\n\nOlá *{{responsavel_nome}}*,\n\nFaltam apenas *{{dias_restantes}} dias* para encerrar o prazo de matrícula de *{{crianca_nome}}*.\n\nData limite: *{{data_limite}}*\n\nCompareça à Secretaria o quanto antes para não perder a vaga!', '["crianca_nome", "responsavel_nome", "dias_restantes", "data_limite", "cmei_nome"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.546918+00'),
('217d7014-6a26-4448-ba63-7464e64e8cd3', 'matricula_confirmada', 'Matrícula Confirmada', 'Enviado após confirmação da matrícula', 'Matrícula Confirmada - {{crianca_nome}}', '<h2>✅ Matrícula Confirmada</h2><p>Parabéns! A matrícula de <strong>{{crianca_nome}}</strong> no CMEI <strong>{{cmei_nome}}</strong> foi confirmada com sucesso.</p><p>Seja bem-vindo(a)!</p>', 'VAGOU: Matricula de {{crianca_nome}} confirmada no CMEI {{cmei_nome}}. Bem-vindo!', '✅ *Matrícula Confirmada*\n\nParabéns! A matrícula de *{{crianca_nome}}* no CMEI *{{cmei_nome}}* foi confirmada com sucesso.\n\nSeja bem-vindo(a)!', '["crianca_nome", "responsavel_nome", "cmei_nome", "turma_nome", "turno"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.619021+00'),
('3cc322b6-9610-47a9-862b-a3a20250691f', 'remanejamento_concluido', 'Remanejamento Concluído', 'Enviado quando remanejamento é efetivado', 'Remanejamento Aprovado - {{crianca_nome}}', '<h2>✅ Remanejamento Aprovado</h2><p>O remanejamento de <strong>{{crianca_nome}}</strong> para o CMEI <strong>{{cmei_nome}}</strong> foi aprovado!</p><p>Por favor, compareça à nova unidade para confirmar a matrícula.</p>', 'VAGOU: Remanejamento de {{crianca_nome}} aprovado para {{cmei_nome}}. Compareca para confirmar.', '✅ *Remanejamento Aprovado*\n\nO remanejamento de *{{crianca_nome}}* para o CMEI *{{cmei_nome}}* foi aprovado!\n\nPor favor, compareça à nova unidade para confirmar a matrícula.', '["crianca_nome", "responsavel_nome", "cmei_nome", "turma_nome"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.906178+00'),
('9f2dd345-227c-4e69-a91c-08ea7454bab6', 'documento_recusado', 'Documento Recusado', 'Enviado quando um documento é recusado', 'Problema na Documentação - {{crianca_nome}}', '<h2>❌ Problema na Documentação</h2><p>Olá <strong>{{responsavel_nome}}</strong>,</p><p>Alguns documentos de <strong>{{crianca_nome}}</strong> precisam ser reenviados.</p><div style=''background-color: #fef2f2; padding: 15px; border-radius: 5px; border-left: 5px solid #ef4444; margin: 20px 0;''><p style=''margin: 0;''><strong>Motivo:</strong> {{motivo}}</p></div><p>Acesse o sistema para regularizar a situação.</p>', 'VAGOU: Documento de {{crianca_nome}} recusado. Acesse o app para reenviar. Motivo: {{motivo}}', '❌ *Problema na Documentação*\n\nOlá *{{responsavel_nome}}*,\n\nAlguns documentos de *{{crianca_nome}}* precisam ser reenviados.\n\nMotivo: {{motivo}}\n\nAcesse o sistema para regularizar a situação.', '["crianca_nome", "responsavel_nome", "motivo", "lista_documentos"]'::jsonb, true, 6, '2025-12-04 16:17:18.317392+00', '2025-12-18 02:45:04.992324+00'),
('755723a3-0143-41ae-84c5-0cc1237d130e', 'desistencia', 'Desistência Registrada', 'Notificação enviada quando uma criança é marcada como desistente', 'Desistência Registrada - {{crianca_nome}}', '<h2>❌ Desistência Registrada</h2><p>Confirmamos o cancelamento da inscrição de <strong>{{crianca_nome}}</strong> conforme solicitado.</p><p>Caso mude de ideia, será necessário realizar uma nova inscrição.</p>', 'VAGOU: Cancelamento da inscricao de {{crianca_nome}} confirmado.', '❌ *Desistência Registrada*\n\nConfirmamos o cancelamento da inscrição de *{{crianca_nome}}* conforme solicitado.\n\nCaso mude de ideia, será necessário realizar uma nova inscrição.', '["crianca_nome", "responsavel_nome", "motivo", "municipio_nome", "secretaria_nome"]'::jsonb, true, 11, '2025-12-11 01:08:19.237567+00', '2025-12-18 02:45:05.167582+00'),
('b304824b-2bee-4df3-9d4e-8cb5cfe7fc79', 'inscricao_realizada', 'Inscrição Realizada', '', 'Confirmação de Inscrição - {{crianca_nome}}', '<h2>Inscrição Realizada com Sucesso!</h2><p>Olá <strong>{{responsavel_nome}}</strong>,</p><p>A inscrição de <strong>{{crianca_nome}}</strong> foi realizada com sucesso no sistema.</p><ul><li><strong>Data:</strong> {{data_inscricao}}</li></ul><p>Você pode acompanhar a posição na fila de espera acessando the sistema ou nosso aplicativo.</p><hr/><p><small>Este é um e-mail automático, por favor não responda.</small></p>', 'VAGOU: Inscricao de {{crianca_nome}} realizada! Acompanhe a posicao na fila pelo app.', '✅ *Inscrição Realizada com Sucesso!*\n\nOlá *{{responsavel_nome}}*,\n\nA inscrição de *{{crianca_nome}}* foi realizada com sucesso.\n\n📅 Data: {{data_inscricao}}\n\nVocê pode acompanhar a posição na fila pelo aplicativo ou site.', '["crianca_nome", "responsavel_nome", "posicao_fila", "turma_nome", "data_inscricao"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.342841+00'),
('ee0c9699-d138-4fdf-bbd7-de932818de80', 'fim_fila', 'Movido para Fim da Fila', 'Enviado quando criança vai para fim da fila', 'Atualização de Fila - {{crianca_nome}}', '<h2>⚠️ Atualização de Fila</h2><p>Olá <strong>{{responsavel_nome}}</strong>,</p><p>Informamos que a inscrição de <strong>{{crianca_nome}}</strong> foi movida para o fim da fila.</p><p><strong>Motivo:</strong> {{motivo}}</p>', 'VAGOU: Inscricao de {{crianca_nome}} movida para the fim da fila. Motivo: {{motivo}}', '⚠️ *Atualização de Fila*\n\nOlá *{{responsavel_nome}}*,\n\nInformamos que a inscrição de *{{crianca_nome}}* foi movida para o fim da fila.\n\nMotivo: {{motivo}}', '["crianca_nome", "responsavel_nome", "motivo", "posicao_fila"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.711415+00'),
('f53fbadc-5f95-4aca-b696-047b8d0d6030', 'remanejamento_solicitado', 'Remanejamento Solicitado', 'Confirmação de solicitação de remanejamento', 'Solicitação de Remanejamento - {{crianca_nome}}', '<h2>🔄 Solicitação de Remanejamento</h2><p>Recebemos sua solicitação de remanejamento para <strong>{{crianca_nome}}</strong>.</p><p><strong>CMEI Solicitado:</strong> {{cmei_nome}}</p><p>Aguarde, entraremos em contato assim que houver disponibilidade.</p>', 'VAGOU: Solicitacao de remanejamento para {{crianca_nome}} recebida. Aguarde contato.', '🔄 *Solicitação de Remanejamento*\n\nRecebemos sua solicitação de remanejamento para *{{crianca_nome}}*.\n\nCMEI Solicitado: {{cmei_nome}}\n\nAguarde, entraremos em contato assim que houver disponibilidade.', '["crianca_nome", "responsavel_nome", "cmei_atual", "cmei_destino"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.817561+00'),
('433fc923-6e45-4051-bb8d-05096d693fd5', 'documentos_aprovados', 'Documentos Aprovados', 'Enviado quando todos os documentos são aprovados', 'Documentação Aprovada - {{crianca_nome}}', '<h2>✅ Documentação Aprovada</h2><p>Os documentos de <strong>{{crianca_nome}}</strong> foram validados com sucesso!</p><p>Aguarde as próximas etapas.</p>', 'VAGOU: Documentos de {{crianca_nome}} aprovados! Aguarde proximas etapas.', '✅ *Documentação Aprovada*\n\nOs documentos de *{{crianca_nome}}* foram validados com sucesso!\n\nAguarde as próximas etapas.', '["crianca_nome", "responsavel_nome", "cmei_nome", "data_limite"]'::jsonb, true, 7, '2025-12-04 16:17:18.317392+00', '2025-12-18 02:45:05.081728+00'),
('33820cb1-778e-47d4-b2f0-b45c1ffca66c', 'recusa', 'Recusa de Vaga', 'Notificação enviada quando o responsável recusa a vaga oferecida', 'Recusa de Vaga - {{crianca_nome}}', '<h2>🚫 Recusa de Vaga Registrada</h2><p>Confirmamos que você optou por não aceitar a vaga no CMEI <strong>{{cmei_nome}}</strong> para <strong>{{crianca_nome}}</strong>.</p><p>Sua inscrição retornará para a fila de espera conforme as regras vigentes.</p>', 'VAGOU: Recusa de vaga para {{crianca_nome}} no CMEI {{cmei_nome}} confirmada.', '🚫 *Recusa de Vaga Registrada*\n\nConfirmamos que você optou por não aceitar a vaga no CMEI *{{cmei_nome}}* para *{{crianca_nome}}*.\n\nSua inscrição retornará para a fila de espera conforme as regras vigentes.', '["crianca_nome", "responsavel_nome", "cmei_nome", "turma_nome", "motivo", "municipio_nome", "secretaria_nome"]'::jsonb, true, 12, '2025-12-11 01:08:19.237567+00', '2025-12-18 02:45:05.263566+00'),
('ee3b8802-36ad-4e69-ad6f-ecabb60fcf55', 'convocacao', 'Convocação para Matrícula', 'Enviado quando criança é convocada', 'CONVOCAÇÃO DE VAGA - {{crianca_nome}}', '<h2>🎉 Parabéns! Vaga Disponível</h2><p>Olá <strong>{{responsavel_nome}}</strong>,</p><p>Temos uma ótima notícia! Surgiu uma vaga para <strong>{{crianca_nome}}</strong> no CMEI <strong>{{cmei_nome}}</strong> ({{turma_nome}}).</p><div style=''background-color: #f0f9ff; padding: 15px; border-radius: 5px; border-left: 5px solid #0ea5e9; margin: 20px 0;''><p style=''margin: 0;''><strong>⚠️ ATENÇÃO AOS PRAZOS</strong></p><p>Você tem até <strong>{{data_limite}}</strong> ({{prazo_dias}} dias) para comparecer à Secretaria de Educação.</p></div><p><strong>Local de Comparecimento:</strong><br/>{{secretaria_nome}}</p><p>Não perca o prazo! O não comparecimento pode implicar na perda da vaga.</p>', 'VAGOU: Vaga para {{crianca_nome}} no CMEI {{cmei_nome}}! Compareca a Secretaria ate {{data_limite}}.', '🎉 *Parabéns! Vaga Disponível*\n\nOlá *{{responsavel_nome}}*,\n\nSurgiu uma vaga para *{{crianca_nome}}* no CMEI *{{cmei_nome}}* ({{turma_nome}}).\n\n⚠️ *Atenção aos prazos:*\nVocê tem até *{{data_limite}}* ({{prazo_dias}} dias) para comparecer à Secretaria de Educação.\n\n📍 Secretaria: {{secretaria_nome}}\n\nNão perca o prazo!', '["crianca_nome", "responsavel_nome", "cmei_nome", "turma_nome", "data_limite", "prazo_dias", "endereco_cmei"]'::jsonb, true, 0, '2025-12-04 15:46:21.692094+00', '2025-12-18 02:45:04.452771+00')
